mapper.update:
update `score`
score = #{score}, status = #{status}, cheat = #{cheat},
where id = #{id}

mapper.select:
select score.id, score.student_id, score.test_id, score.score, score.status, score.cheat,
       student.name as studentName, student.username as studentNumber,
       test.id as testId, test.name as testName, test.test_paper_id as testPaperId,
       test.start as start, test.end as end, test.duration as duration,
       test.release_time as releaseTime, test.weather_check as weatherCheck, test_paper.teacher_id as teacherId
from `score`
left join student on score.student_id = student.id
left join test on score.test_id = test.id
left join test_paper on test.test_paper_id = test_paper.id

     and score.student_id = #{studentId}
     and test_paper.teacher_id = #{teacherId}
     and score.test_id = #{testId}
     and score.status = #{status}

select score.*, student.name as studentName, student.username as studentNumber from `score`
left join student on score.student_id = student.id
left join student_clazz sc on student.id = sc.student_id
where score.test_id = #{testId}

    and sc.clazz_id = #{clazzId}

order by student.name

SELECT q.id, q.question_stem as questionStem, qt.name as questionTypeName, qt.variety as questionTypeVariety, tpq.score as typeScore, (SELECT COUNT(*) FROM score s LEFT JOIN student st ON s.student_id = st.id LEFT JOIN student_clazz sc ON st.id = sc.student_id WHERE s.test_id = #{testId} AND s.cheat != 1
AND sc.clazz_id = #{clazzId}
) as totalCount, COUNT(DISTINCT CASE WHEN a.status = '已批改' THEN a.score_id END) as gradedCount FROM test t INNER JOIN test_paper tp ON t.test_paper_id = tp.id INNER JOIN test_paper_question tpq ON tp.id = tpq.test_paper_id INNER JOIN question q ON tpq.question_id = q.id INNER JOIN question_type qt ON q.question_type_id = qt.id LEFT JOIN answer a ON a.test_paper_question_id = tpq.id AND a.score_id IN ( SELECT s.id FROM score s LEFT JOIN student st ON s.student_id = st.id LEFT JOIN student_clazz sc ON st.id = sc.student_id WHERE s.test_id = #{testId} AND s.cheat != 1
AND sc.clazz_id = #{clazzId}
) WHERE t.id = #{testId} AND qt.name NOT IN ('单选', '多选', '判断') AND tpq.type IN ('common', 'father') GROUP BY q.id, q.question_stem, qt.name, qt.variety, tpq.score, tpq.id ORDER BY tpq.id

mapper.update:
UPDATE answer a
INNER JOIN test_paper_question tpq ON a.test_paper_question_id = tpq.id
SET a.score = #{score},
    a.status = '已批改'
WHERE a.score_id = #{scoreId}
AND tpq.question_id = #{questionId}

UPDATE answer a
INNER JOIN test_paper_question tpq ON a.test_paper_question_id = tpq.id
SET a.status = '已批改'
WHERE a.score_id = #{scoreId}
AND tpq.question_id = #{questionId}
